    Для Каждого Стр Из ИсходнаяТаблица Цикл
        Если Не УникальныеЗначения.Содержит(Стр[КолонкаГруппировки]) Тогда
            УникальныеЗначения.Добавить(Стр[КолонкаГруппировки]);
        КонецЕсли;
    КонецЦикла;

    // Формируем итоговую таблицу путем подсчета суммы по каждому уникальному значению
    Для каждого Значение Из УникальныеЗначения Цикл
        СуммаПоЗначению = 0;

