	ДлинаСтроки2 = СтрДлина(Строка2);

	Если ДлинаСтроки1 = 0 Тогда
		Возврат ДлинаСтроки2;
	КонецЕсли;

	Если ДлинаСтроки2 = 0 Тогда
		Возврат ДлинаСтроки1;
	КонецЕсли;

	Массив := Новый Массив(ДлинаСтроки1 + 1);
	Для И = 0 По ДлинаСтроки1 Цикл
		Массив[И] := И;
	КонецЦикла;

	Для J = 1 По ДлинаСтроки2 Цикл
		НовыйМассив := Новый Массив(ДлинаСтроки1 + 1);
		НовыйМассив[0] := J;
		Для И = 1 По ДлинаСтроки1 Цикл
			Если Сред(Строка1, И, 1) = Сред(Строка2, J, 1) Тогда
				Стоимость = 0;
			Иначе
				Стоимость = 1;
			КонецЕсли;
			НовыйМассив[И] = Мин(Мин(НовыйМассив[И - 1] + 1, Массив[И] + 1), Массив[И - 1] + Стоимость);
		КонецЦикла;
		Массив = НовыйМассив;
	КонецЦикла;

	Возврат Массив[ДлинаСтроки1];
