Функция РедакционноеРасстояниеЛевенштейна(Строка1, Строка2)

    ДлинаСтроки1 = СтрДлина(Строка1);
    ДлинаСтроки2 = СтрДлина(Строка2);

    // Создаём матрицу расстояний
    Матрица = Новый Матрица(ДлинаСтроки1 + 1, ДлинаСтроки2 + 1);

    // Инициализация первой строки и первого столбца матрицы
    Для Инд = 0 По ДлинаСтроки1 Цикл
        Матрица[Инд][0] = Инд;
    КонецЦикла;

    Для Инд = 0 По ДлинаСтроки2 Цикл
        Матрица[0][Инд] = Инд;
    КонецЦикла;

    // Заполнение матрицы
    Для Инд1 = 1 По ДлинаСтроки1 Цикл
        Для Инд2 = 1 По ДлинаСтроки2 Цикл
            Если Сред(Строка1, Инд1, 1) = Сред(Строка2, Инд2, 1) Тогда
                Стоимость = 0;
            Иначе
                Стоимость = 1;
            КонецЕсли;

            Матрица[Инд1][Инд2] = Мин(
                Матрица[Инд1 - 1][Инд2] + 1, // удаление
                Матрица[Инд1][Инд2 - 1] + 1, // вставка
                Матрица[Инд1 - 1][Инд2 - 1] + Стоимость // замена
            );
        КонецЦикла;
    КонецЦикла;

    Возврат Матрица[ДлинаСтроки1][ДлинаСтроки2];

