Функция РасстЛевенштейна(Строка1, Строка2)
    Длина1 = СтрДлина(Строка1);
    Длина2 = СтрДлина(Строка2);

    МассивРасстояний = Новый Массив(Длина1 + 1, Длина2 + 1); // Создаем двумерный массив расстояний

    Для i = 0 По Длина1 Цикл
        МассивРасстояний[i+1][1] = i; // Инициализация первой колонки матрицы
    КонецЦикла;

    Для j = 0 По Длина2 Цикл
        МассивРасстояний[1][j+1] = j; // Инициализация первой строки матрицы
    КонецЦикла;

    Для i = 1 По Длина1 Цикл
        Символ1 = Сред(Строка1, i, 1);

        Для j = 1 По Длина2 Цикл
            Символ2 = Сред(Строка2, j, 1);

            Если Символ1 = Символ2 Тогда
                СтоимостьЗамены = 0;
            Иначе
                СтоимостьЗамены = 1;
            КонецЕсли;

            Замена = МассивРасстояний[i][j] + СтоимостьЗамены;
            Вставка = МассивРасстояний[i+1][j] + 1;
            Удаление = МассивРасстояний[i][j+1] + 1;

            МассивРасстояний[i+1][j+1] = Мин(Замена, Вставка, Удаление);
        КонецЦикла;
    КонецЦикла;

    Возврат МассивРасстояний[Длина1+1][Длина2+1];
КонецФункции

Функция РедактированиеРасстояние(ПерваяСтрока, ВтораяСтрока)
// Инициализация матрицы расстояний
Длина1 = СтрДлина(ПерваяСтрока);
Длина2 = СтрДлина(ВтораяСтрока);
Матрица = Новый Массив(Длина1 + 1, Новый Массив(Длина2 + 1));
Для Я := 0 По Длина1 Цикл
Матрица[Я][0] = Я;
КонецЦикла;
Для Х := 0 По Длина2 Цикл
Матрица[0][Х] = Х;
КонецЦикла;

// Заполнение матрицы по алгоритму Левенштейна
Для Я = 1 По Длина1 Цикл
Симв1 = Сред(ПерваяСтрока, Я, 1);
Для Х = 1 По Длина2 Цикл
Симв2 = Сред(ВтораяСтрока, Х, 1);
СтоимостьЗамены = Если(Симв1 = Симв2, 0, 1);
Минимум = Матрица[Я - 1][Х] + 1; // Удаление
Если Матрица[Я][Х - 1] + 1 < Минимум Тогда
Минимум = Матрица[Я][Х - 1] + 1; // Вставка
КонецЕсли;
Если Матрица[Я - 1][Х - 1] + СтоимостьЗамены < Минимум Тогда
Минимум = Матрица[Я - 1][Х - 1] + СтоимостьЗамены; // Замена
КонецЕсли;
Матрица[Я][Х] = Минимум;
КонецЦикла;
КонецЦикла;
Возврат Матрица[Длина1][Длина2];
КонецФункции

