Функция ПолучитьПростыеЧисла(Граница)
    // Если граница меньше 2, простых чисел нет
    Если Граница < 2 Тогда
        Возврат Новый Массив;
    КонецЕсли;

    // Инициализация решета: 1 означает "возможно простое"
    МассивЧисел = Новый Массив;
    Для сч = 0 По Граница Цикл
        МассивЧисел.Добавить(1);
    КонецЦикла;

    // 0 и 1 не являются простыми числами
    МассивЧисел[0] = 0;
    МассивЧисел[1] = 0;

    // Основной цикл решета Эратосфена
    КореньГраницы = Корень(Граница);
    Для к = 2 По Цел(КореньГраницы) Цикл
        Если МассивЧисел[к] = 1 Тогда
            // Помечаем все кратные числа как составные
            Для м = к * к По Граница Шаг к Цикл
                МассивЧисел[м] = 0;
            КонецЦикла;
        КонецЕсли;
    КонецЦикла;

    // Сборка результата
    Результат = Новый Массив;
    Для сч = 2 По Граница Цикл
        Если МассивЧисел[сч] = 1 Тогда
            Результат.Добавить(сч);
        КонецЕсли;
    КонецЦикла;

    Возврат Результат;
