                Шаг += Число;
            КонецЦикла;
        КонецЕсли;
    КонецЦикла;

    ПростыеЧисла = Новый Массив;
    Для i = 2 По Граница Цикл
        Если Флаги[i] Тогда
            ПростыеЧисла.Добавить(i);
        КонецЕсли;
    КонецЦикла;

    Возврат ПростыеЧисла;
