Функция ПростыеЧисла(Граница как Число)
    Если Граница < 2 Тогда
        Возврат ПустойСписокЗначений()
    КонецЕсли;

    // Создаем булевый массив размером Граница+1
    МассивПростых = Новый Массив(Граница + 1);
    Для Инд = 0 По Граница Цикл
        МассивПростых[Инд] = Истина;  
    КонецЦикла;

    // Отмечаем числа кратные 2 начиная с 4
    Для Инд = 4 По Граница Шаг 2 Цикл
        МассивПростых[Инд] = Ложь;
    КонецЦикла;

    // Проходим по числам от 3 до корня из Границы
    Для Инд = 3 По ЦелоеЧисло(КвадратныйКореньОт(Граница)) Цикл
        Если МассивПростых[Инд] Тогда
            // Отмечаем все кратные текущему числу начиная с квадрата
            Для ИндКр = Инд * Инд По Граница Шаг Инд
                МассивПростых[ИндКр] = Ложь;
            КонецЦикла;
        КонецЕсли;
    КонецЦикла;

    // Собираем простые числа
    Результат = Новый СписокЗначений();
    Для Инд = 2 По Граница Цикл
        Если МассивПростых[Инд] Тогда
            Результат.Добавить(Инд);
        КонецЕсли;
    КонецЦикла;

    Возврат Результат;
КонецФункции
